class Calculator {
    // Different parameter counts:
    static int add(int a, int b) {
        return a + b;
    }
    static int add(int a, int b, int c) {
        return a + b + c;
    }
    // Different parameter types:
    static double add(double a, double b) {
        return a + b;
    }
}

System.out.println(Calculator.add(2,3));      // 5 (int,int)
System.out.println(Calculator.add(1,2,3));    // 6 (int,int,int)
System.out.println(Calculator.add(1.5,2.5)); // 4.0 (double,double)

static int factorial(int n) {
    if (n <= 1) return 1;   // BASE CASE — stop!
    return n * factorial(n - 1); // recursive call
}

System.out.println(factorial(5));
// factorial(5) = 5 * factorial(4)
//              = 5 * 4 * factorial(3)
//              = 5 * 4 * 3 * factorial(2)
//              = 5 * 4 * 3 * 2 * factorial(1)
//              = 5 * 4 * 3 * 2 * 1 = 120

static int fib(int n) {
    if (n <= 1) return n;  // base cases: fib(0)=0,fib(1)=1
    return fib(n-1) + fib(n-2);
}

System.out.println(fib(6)); // 8
// 0,1,1,2,3,5,8 ← index 6 = 8

